// Enable all grids and lines
GridLinesMgr.setFlagGridlines(true);

// Disable all grids and lines
GridLinesMgr.setFlagGridlines(false);

var isVisible = GridLinesMgr.getFlagGridlines();
core.debug("Grids enabled: " + isVisible);

if(GridLinesMgr.getFlagGridlines()) {
    core.debug("Grid elements are enabled");
} else {
    core.debug("All grid elements are disabled");
}

// Enable all celestial coordinate grids
GridLinesMgr.setFlagAllGrids(true);

// Disable all grids
GridLinesMgr.setFlagAllGrids(false);

// Enable all great circle lines
GridLinesMgr.setFlagAllLines(true);

// Disable all lines
GridLinesMgr.setFlagAllLines(false);

// Enable all celestial reference points
GridLinesMgr.setFlagAllPoints(true);

// Disable all points
GridLinesMgr.setFlagAllPoints(false);

// Show azimuthal (altitude/azimuth) grid
GridLinesMgr.setFlagAzimuthalGrid(true);

// Hide azimuthal grid
GridLinesMgr.setFlagAzimuthalGrid(false);

var isVisible = GridLinesMgr.getFlagAzimuthalGrid();
core.debug("Azimuthal grid visible: " + isVisible);

// Set azimuthal grid to light blue
var lightBlue = core.vec3f(0.5, 0.7, 1.0);
GridLinesMgr.setColorAzimuthalGrid(lightBlue);

var color = GridLinesMgr.getColorAzimuthalGrid();
core.debug("Color: RGB(" + color[0] + ", " + color[1] + ", " + color[2] + ")");

// Show equatorial grid
GridLinesMgr.setFlagEquatorGrid(true);

// Hide equatorial grid
GridLinesMgr.setFlagEquatorGrid(false);

// Show celestial equator
GridLinesMgr.setFlagEquatorLine(true);

// Hide celestial equator
GridLinesMgr.setFlagEquatorLine(false);

// Show ecliptic path
GridLinesMgr.setFlagEclipticLine(true);

// Hide ecliptic path
GridLinesMgr.setFlagEclipticLine(false);

// Show dates along the ecliptic (Sun's position)
GridLinesMgr.setFlagEclipticDatesLabeled(true);

var visible = GridLinesMgr.getFlagEclipticDatesLabeled();
core.debug("Ecliptic date labels visible: " + visible);

// Show the path of celestial pole precession
GridLinesMgr.setFlagPrecessionCircles(true);

var visible = GridLinesMgr.getFlagPrecessionCircles();

// Show the meridian (north-south line through zenith)
GridLinesMgr.setFlagMeridianLine(true);

var visible = GridLinesMgr.getFlagMeridianLine();

// Show the horizon circle
GridLinesMgr.setFlagHorizonLine(true);

// Hide the horizon circle
GridLinesMgr.setFlagHorizonLine(false);

// Show the Milky Way's equatorial plane
GridLinesMgr.setFlagGalacticEquatorLine(true);

var visible = GridLinesMgr.getFlagGalacticEquatorLine();

// Show the equinoctial and solstitial colures
GridLinesMgr.setFlagColureLines(true);

var visible = GridLinesMgr.getFlagColureLines();

// Show the opposition/conjunction longitude line
GridLinesMgr.setFlagLongitudeLine(true);

var visible = GridLinesMgr.getFlagLongitudeLine();

// Show the northern and southern circumpolar circles
GridLinesMgr.setFlagCircumpolarCircles(true);

var visible = GridLinesMgr.getFlagCircumpolarCircles();

// Show Earth's umbra circle (for eclipse prediction)
GridLinesMgr.setFlagUmbraCircle(true);

var visible = GridLinesMgr.getFlagUmbraCircle();

// Show Earth's penumbra circle
GridLinesMgr.setFlagPenumbraCircle(true);

var visible = GridLinesMgr.getFlagPenumbraCircle();

// Show the celestial poles (J2000 epoch)
GridLinesMgr.setFlagCelestialJ2000Poles(true);

var visible = GridLinesMgr.getFlagCelestialJ2000Poles();

// Show the current celestial poles
GridLinesMgr.setFlagCelestialPoles(true);

var visible = GridLinesMgr.getFlagCelestialPoles();

// Show zenith and nadir points
GridLinesMgr.setFlagZenithNadir(true);

var visible = GridLinesMgr.getFlagZenithNadir();

// Mark the center of our galaxy
GridLinesMgr.setFlagGalacticCenter(true);

var visible = GridLinesMgr.getFlagGalacticCenter();

// Mark the point opposite the Sun
GridLinesMgr.setFlagAntisolarPoint(true);

var visible = GridLinesMgr.getFlagAntisolarPoint();

// Mark the center of Earth's umbra for eclipse prediction
GridLinesMgr.setFlagUmbraCenterPoint(true);

var visible = GridLinesMgr.getFlagUmbraCenterPoint();

// Show the direction of Earth's motion through space
GridLinesMgr.setFlagApexPoints(true);

var visible = GridLinesMgr.getFlagApexPoints();

if(GridLinesMgr.getFlagApexPoints()) {
    core.debug("Apex and antapex points visible");
}

// Thick lines for better visibility
GridLinesMgr.setLineThickness(2.0);

// Thin, elegant lines
GridLinesMgr.setLineThickness(1.0);

var thickness = GridLinesMgr.getLineThickness();
core.debug("Line thickness: " + thickness);

// Larger points for better visibility
GridLinesMgr.setPointSize(8.0);

// Smaller points
GridLinesMgr.setPointSize(5.0);

var size = GridLinesMgr.getPointSize();
core.debug("Point size: " + size);

// Coarse grid (fewer lines)
GridLinesMgr.setGridSpacingMultiplier(0.5);

// Fine grid (more lines)
GridLinesMgr.setGridSpacingMultiplier(2.0);

// Normal grid spacing
GridLinesMgr.setGridSpacingMultiplier(1.0);

var multiplier = GridLinesMgr.getGridSpacingMultiplier();
core.debug("Grid spacing multiplier: " + multiplier);
